UPDATE public.site_projects SET body = 'תכנית למנהיגות והתפתחות אישית ליוצאי יחידות מיוחדות בשיתוף עמותת הסיירת הצפונית יוצאת לדרך!

תוכנית חצי שנתית בחניכה אישית של פרד קופמן – סמנכ״ל המנהיגות של גוגל העולמית.

אנחנו שמחים לבשר על מיזם משותף להקמת תוכנית מצטיינים למנהיגות שמטרתה להיות אקסלרטור למנהיגי דור העתיד.

מבנה תוכנית המנהיגות הינו פורץ דרך ומגובה בעולם תוכן שלם של ערכים, מודעות והתפתחות אישית.

התוכנית היא פרי יוזמה פילנתרופית משותפת שני מובילי דיעה עולמיים: פרד קופמן וריד הופמן, יחד עם 10 עמותות בוגרים של יחידות העילית של צה&quot;ל.

פרד קופמן הוא סמנכ&quot;ל המנהיגות בגוגל העולמית והיה גם מאמנם האישי של שריל סנדברג ( COO Facebook), ג''ף ווינר (CEO Linkedin) וסאטייה נאדלה (CEO Microsoft), להלן קישור לראיון עמו בגלובס.

ריד הופמן הוא אחד מבכירי עמק הסיליקון (מייסד Linkedin, Airbnb, Paypal) והתורם הכספי העיקרי להקמת המיזם. פרד קופמן ילמד את התוכנית באופן אישי וריד הופמן יעביר וובינר פרטי למשתתפים במהלכה.

התכנית הינה אינטר-דיסציפלינרית ותשלב בין תכנים ''קשים'' של ניהול צוות, ניהול מוכוון מטרה, פתרון קונפליקטים וכדומה,עבור דרך כלכלה ופילוסופיה ועד לתכנים ''רכים'' יותר כגון פסיכולוגיה ומיינדפולנס. הכל מתוך גישה שמנהיגות נבנית במודל של 360 מעלות.

אנחנו מאמינים שמהמשתתפים האיכותיים, יוצאי יחידות העילית המשתתפות, יחד עם התכנים היחודיים הנ&quot;ל, יצמחו לא מעט מנהיגים שיהוו מודל לחיקוי וגאווה מבחינה עסקית, חברתית פוליטית ומעל לכל – ערכית.', gallery_urls = '["/assets/projects/leaders-gallery-1.jpg"]'::jsonb WHERE slug = 'leaders';
UPDATE public.site_projects SET body = 'עמותת הסיירת הצפונית בשיתוף פעולה עם מרכז צעירים בת ים וארגון תופסים כיוון הארצי מפעילה מיזם חברתי אשר מטרתו היא מימוש ומיצוי הפוטנציאל התעסוקתי ופיתוח הקריירה, של צעירים אקדמאים מהפריפריה קידום שוויון הזדמנויות בתעסוקה לחיזוק החוסן החברתי – כלכלי בישראל. בוגרי היחידה מתנדבים כמרצים בתוכנית וכמנטורים המלווים את הצעירים בתהליך פיתוח עצמי ופיתוח קריירה. במסגרת המיזם לכל משתתף מוצמד מנטור אשר מלווה אותו לכל אורך התכנית ומעניק לו השראה, מידע, לווי ותמיכה. במפגשי התכנית ובמפגשים אישיים מתקיים קשר בלתי אמצעי של המשתתפים עם מומחים בתחומי התעסוקה השונים. 

מרגיש שיש לך מה לתרום לצעירים בתחילת דרכם? רוצה להעניק מניסיון החיים שלך לטובת שיפור החברה בישראל? יש לנו הזדמנות מדהימה עבורך להצטרף אלינו כעמית לדרך. מוזמנים ליצור קשר במייל: tofsimkivoun.egoz@gmail.com', gallery_urls = '["/assets/projects/catching-direction-gallery-1.jpg"]'::jsonb WHERE slug = 'catching-direction';
UPDATE public.site_projects SET body = 'העמותה מעביר סדנת הכנה לאזרחות לכל מחזור לקראת שחרור מהיחדה. בסדנה, חיילי היחידה שלקראת שחרור נפגשים עם מעסיקים מובילים במשק, עוברים הרצאות הכנה ללימודים גבוהים, נחשפים לתכנים רלוונטים למטיילים ומיזמים חברתיים. אך הכי חשוב, האירוע נועד לקבל את אותם המשוחררים בזרועות פתוחות לאזרחות, להקל ולסייע להם בתחילת החיים הבוגרים שלהם אחרי השירות הצבאי, לעודד אותם לתכנן את עתידם ולהצליח בחיים על פי הקריטריונים שלהם להצלחה. המיזם רץ כבר שנתיים, וכתוצאה מכך משוחררים רבים סיימו את שירותם הצבאי כאשר עבודה מחכה להם בעת שיחרורם, קיבלו הכוונה ללימודים ולתכנון עתידם.', gallery_urls = '["/assets/projects/release-gallery-1.jpg"]'::jsonb WHERE slug = 'release';
UPDATE public.site_projects SET body = 'מאז הוקמה בשנות ה-50 ניצבת יחידת אגוז, יחידת הקומנדו של זרוע היבשה, בחוד החנית של צה&quot;ל בלחימה בטרור ובהגנה על גבולות מדינת ישראל – בלבנון, סוריה, איו&quot;ש ועזה. לוחמי היחידה עוברים מסלול הכשרה מפרך על מנת שיוכלו להגן על אזרחי המדינה ולאפשר להם לחיות בה בבטחה. לנוכח המציאות שבה אנו חיים והאיומים אשר אינם חדלים לרגע מלרחף על ראשינו, תעוזתם ומקצועיותם של לוחמי יחידת אגוז עומדות במבחן בהצלחה פעם אחר פעם, במלחמות ובפעולות חשאיות, ותורמות לחיזוק עוצמתו של צה&quot;ל וליכולתה של ישראל לשמר את עליונותה הצבאית. עמידה זו גובה לא פעם מחיר כבד, בגוף ובנפש. נוסף על 68 חללי היחידה אשר נפלו על הגנת המולדת, ישנם עוד מאות לוחמים אשר נושאים עדיין בגופם ובנפשם את צלקות הקרב. בעבורם ההקרבה לא הסתיימה עם פשיטת המדים והיציאה לאזרחות. היא ממשיכה לבוא לידי ביטוי בהתמודדות יומיומית עם קשיים בזוגיות, בהורות, ובחיים המקצועיים. אנו, אחיהם לנשק של פצועי היחידה, חשים אחריות כלפי השתלבותם של פצועי היחידה באזרחות ורואים לעצמנו חובה קדושה להשתתף בנשיאת העול המוטל על כתפיהם. עמותת אגוז, המורכבת מבוגרי היחידה לדורותיה, משתדלת לתת מענה בדרכים שונות לאתגרים הרבים שעמם מתמודדים הלוחמים אשר בעבורם הקרב ההוא לא תם. בימים אלו משיקה העמותה קמפיין מימון המונים במטרה להרחיב את פעילותה. אנו פונים אליכם, בבקשה לתת יד ולסייע לנו במשימה שהצבנו לעצמנו – לאפשר לגיבורינו לחיות חיים רגילים ככל הניתן, על אף הקשיים הכרוכים בכך ועל אף המחיר שאותו הם ומשפחותיהם שילמו, ומשלמים עדיין.

לדף התרומה', gallery_urls = '["/assets/projects/ambassadors-gallery-1.jpg","/assets/projects/ambassadors-gallery-2.jpg"]'::jsonb WHERE slug = 'ambassadors';
UPDATE public.site_projects SET body = 'נכנסים מתחת לאלונקה ומתקדמים יחד לעבר העתיד. אנו מזמינים אתכם, בוגרי היחידה, מי שזקוק לסיוע, אנחנו כאן! נדע להעמיד מענקים ע&quot;מ לסייע למי שזקוק לכך בעת הזו, בכדי לעמוד על הרגליים ולצלוח את התקופה הקרובה. כמובן, כל סיוע נוסף שנדרש- נשמח לסייע ככל האפשר, אנו זמינים 24/7. חשוב לציין ובכדי לשמור על שקיפות והתנהלות תקינה- כלל הבקשות ירוכזו ע&quot;י ועדה מטעם העמותה בליווי משפטי ורו&quot;ח, ע&quot;מ שנוכל לתעדף בין הבקשות, ולתת מענה רחב והוגן ככל הניתן. עמותת אגוז שמחה לעמוד לצדכם גם בימים אלו, ומקווים שבבוא היום מי שקיבל יעניק בחזרה. בשורות טובות ורק בריאות עמותת אגוז בקשות יוגשו למייל: egoz.ezra.haddit@gmail.com כותרת המייל צריכה לכלול בקשת סיוע ואת שם המבקש. לשאלות, מוזמנים לפנות לר&quot;מ:
 תייר – 0502034587 כץ – 0549446155 
**מי שמעוניין לעזור ולתמוך, מוזמן לפנות לטלפונים במודעה', gallery_urls = '[]'::jsonb WHERE slug = 'mutual-help';
UPDATE public.site_projects SET body = 'העמותה יוצרת ומעודדת חיבורים בין בוגרי היחידה, בוגרי יחידת אגוז נמצאים בעמדות בכירות בתחומים מגוונים, העמותה רואה חשיבות גבוהה ביצירת קישורים לטובת הצלחת בוגריה בכל תחום אשר בו הם מעוניינים להצליח. לטובת מטרה זאת, העמותה יצרה קבוצות ווצאפ/ טלגרם לפי תחומי עניין/ תעסוקה, יוזמת מפגשים בעסקים של בוגרי היחידה בהם ניתן להקשיב לסוד הצלחתם ולהיפגש עם בוגרים אחרים בעלי עניין משותף.
 בנוסף העמותה מחברת בוגרי יחידה לפני לימודים, לבוגרים אשר עשו או במהלכו של המסלול האקדמאי שאותו בוגר לפני לימודים מעוניין בו. כל מה שצריך זה לבקש, ליצור קשר עם העמותה או להעלות פוסט בקבוצת הפייסבוק. נטוורקינג הוא כלי חזק, תנצלו אותו לטובתכם.', gallery_urls = '["/assets/projects/networking-gallery-1.png"]'::jsonb WHERE slug = 'networking';
